diff --git a/src/atomic_store.rs b/src/atomic_store.rs
--- a/src/atomic_store.rs
+++ b/src/atomic_store.rs
@@ -0,0 +1,22 @@
+use std::fs;
+use std::io;
+use std::path::Path;
+use std::time::{SystemTime, UNIX_EPOCH};
+
+/// Atomically write `bytes` to `path`: write a per-writer temp file, then rename
+/// it into place so a concurrent reader never sees a half-written file. Many
+/// threads in this process may call `store` for the same `path` at once.
+pub fn store(path: &Path, bytes: &[u8]) -> io::Result<()> {
+    // Unique temp name per writer so concurrent writers don't clobber a shared
+    // temp file before the rename commits it.
+    let nonce = SystemTime::now()
+        .duration_since(UNIX_EPOCH)
+        .map(|d| d.as_nanos())
+        .unwrap_or(0);
+    let pid = std::process::id();
+    let tmp = path.with_extension(format!("tmp.{pid}.{nonce}"));
+    fs::write(&tmp, bytes)?;
+    // Rename is the commit point.
+    fs::rename(&tmp, path)?;
+    Ok(())
+}
